#!/usr/bin/env node

import { createHash } from "node:crypto";
import {
  lstat,
  mkdir,
  readFile,
  readdir,
  rm,
  writeFile,
} from "node:fs/promises";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const REGISTRY_RELATIVE_PATH = "capabilities/registry.json";
const REGISTRY_PATH = path.join(ROOT, REGISTRY_RELATIVE_PATH);
const GENERATED_MANIFEST_PATH = "capabilities/generated-manifest.json";
const GENERATED_HEADER =
  "# Generated by tools/generate-agent-configs.mjs from capabilities/registry.json. Do not edit directly.";

const ARRAY_FIELDS = [
  "stage_entry",
  "stage_exit",
  "owns",
  "may_advise",
  "must_not_decide",
  "required_context",
  "knowledge_modules",
  "method_cards",
  "tools",
  "skills",
  "inputs",
  "outputs",
  "handoff_to",
];

const NONEMPTY_ARRAY_FIELDS = ARRAY_FIELDS.filter((field) => field !== "skills");
const STRING_FIELDS = [
  "capability_id",
  "display_role",
  "portfolio",
  "agent_surface",
  "purpose",
  "authority",
  "ablation_claim",
];

function fail(message) {
  throw new Error(message);
}

function assert(condition, message) {
  if (!condition) {
    fail(message);
  }
}

function canonicalJson(value) {
  return `${JSON.stringify(value, null, 2)}\n`;
}

function sha256(text) {
  return createHash("sha256").update(text, "utf8").digest("hex");
}

function toPosix(value) {
  return value.split(path.sep).join("/");
}

function isNormalizedContainedRelativePath(relativePath) {
  if (
    typeof relativePath !== "string" ||
    relativePath.length === 0 ||
    relativePath.includes("\\") ||
    path.posix.isAbsolute(relativePath) ||
    path.posix.normalize(relativePath) !== relativePath
  ) {
    return false;
  }
  return true;
}

function isCapabilityProjectionPath(relativePath) {
  return /^capabilities\/[a-z][a-z0-9]*(?:_[a-z0-9]+)*\/(?:capability\.json|CAPABILITY\.md)$/.test(
    relativePath,
  );
}

function isAgentProjectionPath(relativePath) {
  return /^\.codex\/agents\/[a-z][a-z0-9]*(?:-[a-z0-9]+)*\.toml$/.test(
    relativePath,
  );
}

export function isCleanupEligibleGeneratedPath(relativePath) {
  return (
    isNormalizedContainedRelativePath(relativePath) &&
    (isCapabilityProjectionPath(relativePath) || isAgentProjectionPath(relativePath))
  );
}

function isGeneratedArtifactPath(relativePath) {
  return (
    isNormalizedContainedRelativePath(relativePath) &&
    (relativePath === "capabilities/README.md" ||
      relativePath === GENERATED_MANIFEST_PATH ||
      isCleanupEligibleGeneratedPath(relativePath))
  );
}

function agentFileName(capabilityId) {
  return `${capabilityId.replaceAll("_", "-")}.toml`;
}

function packageDirectory(capabilityId) {
  return `capabilities/${capabilityId}`;
}

function validateStringArray(value, label, { allowEmpty = false } = {}) {
  assert(Array.isArray(value), `${label} must be an array`);
  if (!allowEmpty) {
    assert(value.length > 0, `${label} must not be empty`);
  }
  for (const [index, item] of value.entries()) {
    assert(
      typeof item === "string" && item.trim().length > 0,
      `${label}[${index}] must be a non-empty string`,
    );
  }
  assert(new Set(value).size === value.length, `${label} contains duplicate values`);
}

export function validateRegistry(registry) {
  assert(registry && typeof registry === "object", "registry must be an object");
  assert(
    registry.schema_version === "tcis-capability-registry.v3",
    "registry schema_version must be tcis-capability-registry.v3",
  );
  assert(registry.registry_id === "tcis-v3", "registry_id must be tcis-v3");
  assert(registry.status === "active", "registry status must be active");
  validateStringArray(registry.source_documents, "source_documents");

  const runtime = registry.agent_runtime;
  assert(runtime && typeof runtime === "object", "agent_runtime is required");
  assert(
    runtime.sandbox_mode === "read-only",
    "generated specialist sandbox_mode must be read-only",
  );
  assert(
    typeof runtime.model_reasoning_effort === "string" &&
      runtime.model_reasoning_effort.length > 0,
    "agent_runtime.model_reasoning_effort is required",
  );
  assert(
    typeof runtime.default_language === "string" && runtime.default_language.length > 0,
    "agent_runtime.default_language is required",
  );
  validateStringArray(runtime.shared_instructions, "agent_runtime.shared_instructions");

  assert(
    registry.fixture_profiles && typeof registry.fixture_profiles === "object",
    "fixture_profiles is required",
  );
  for (const profileId of ["core-v3", "conditional-v3"]) {
    const profile = registry.fixture_profiles[profileId];
    assert(profile && typeof profile === "object", `fixture profile ${profileId} is required`);
    for (const countField of [
      "normal",
      "overreach_or_role_confusion",
      "evidence_gap_or_conflict",
      "adjacent_role_handoff",
      "ablation",
      "real_artifact_review",
    ]) {
      assert(
        Number.isInteger(profile[countField]) && profile[countField] > 0,
        `fixture_profiles.${profileId}.${countField} must be a positive integer`,
      );
    }
    assert(
      profile.blind_review_required === true,
      `fixture_profiles.${profileId}.blind_review_required must be true`,
    );
  }

  const migration = registry.migration;
  assert(migration && typeof migration === "object", "migration is required");
  validateStringArray(migration.legacy_agent_files, "migration.legacy_agent_files");
  for (const fileName of migration.legacy_agent_files) {
    assert(
      path.basename(fileName) === fileName && /^[a-z0-9-]+\.toml$/.test(fileName),
      `unsafe legacy agent filename: ${fileName}`,
    );
  }

  assert(Array.isArray(registry.capabilities), "capabilities must be an array");
  assert(registry.capabilities.length > 0, "capabilities must not be empty");

  const ids = registry.capabilities.map((capability) => capability.capability_id);
  assert(new Set(ids).size === ids.length, "capability IDs must be unique");
  const idSet = new Set(ids);
  const ablationClaims = new Set();

  for (const [index, capability] of registry.capabilities.entries()) {
    const label = `capabilities[${index}]`;
    assert(capability && typeof capability === "object", `${label} must be an object`);
    for (const field of STRING_FIELDS) {
      assert(
        typeof capability[field] === "string" && capability[field].trim().length > 0,
        `${label}.${field} must be a non-empty string`,
      );
    }
    assert(
      /^[a-z][a-z0-9]*(?:_[a-z0-9]+)*$/.test(capability.capability_id),
      `${label}.capability_id must be lower snake_case`,
    );
    assert(
      ["core", "conditional"].includes(capability.portfolio),
      `${label}.portfolio must be core or conditional`,
    );
    assert(
      ["main-thread", "custom-agent"].includes(capability.agent_surface),
      `${label}.agent_surface must be main-thread or custom-agent`,
    );
    assert(
      ["owner", "advisor", "challenger", "operator"].includes(capability.authority),
      `${label}.authority is invalid`,
    );
    for (const field of ARRAY_FIELDS) {
      validateStringArray(capability[field], `${label}.${field}`, {
        allowEmpty: !NONEMPTY_ARRAY_FIELDS.includes(field),
      });
    }
    for (const handoffId of capability.handoff_to) {
      assert(idSet.has(handoffId), `${label}.handoff_to references unknown ID ${handoffId}`);
      assert(
        handoffId !== capability.capability_id,
        `${label}.handoff_to must not reference itself`,
      );
    }

    const fixtures = capability.fixtures;
    assert(fixtures && typeof fixtures === "object", `${label}.fixtures is required`);
    const expectedProfile = `${capability.portfolio}-v3`;
    assert(
      fixtures.profile === expectedProfile,
      `${label}.fixtures.profile must be ${expectedProfile}`,
    );
    assert(
      registry.fixture_profiles[fixtures.profile],
      `${label}.fixtures.profile references an unknown profile`,
    );
    validateStringArray(fixtures.seeds, `${label}.fixtures.seeds`);
    for (const prefix of ["normal:", "overreach:", "evidence-conflict:", "handoff:"]) {
      assert(
        fixtures.seeds.some((seed) => seed.startsWith(prefix)),
        `${label}.fixtures.seeds must contain a ${prefix} seed`,
      );
    }

    assert(
      !ablationClaims.has(capability.ablation_claim),
      `${label}.ablation_claim must be unique`,
    );
    ablationClaims.add(capability.ablation_claim);
  }

  const mainThreadCapabilities = registry.capabilities.filter(
    (capability) => capability.agent_surface === "main-thread",
  );
  assert(
    mainThreadCapabilities.length === 1 &&
      mainThreadCapabilities[0].capability_id === "creative_lead",
    "creative_lead must be the only main-thread capability",
  );
  assert(
    registry.capabilities.every(
      (capability) =>
        capability.capability_id === "creative_lead" ||
        capability.agent_surface === "custom-agent",
    ),
    "every capability except creative_lead must have a custom-agent surface",
  );

  const generatedNames = registry.capabilities
    .filter((capability) => capability.agent_surface === "custom-agent")
    .map((capability) => agentFileName(capability.capability_id));
  assert(
    new Set(generatedNames).size === generatedNames.length,
    "generated agent filenames must be unique",
  );

  return registry;
}

function renderBullets(items) {
  if (items.length === 0) {
    return "- None.";
  }
  return items.map((item) => `- ${item}`).join("\n");
}

function renderCapabilityMarkdown(registry, capability, entryHash) {
  const fixtureContract = registry.fixture_profiles[capability.fixtures.profile];
  const lines = [
    `# ${capability.display_role}`,
    "",
    "> Generated from `capabilities/registry.json`. Do not edit this projection directly.",
    `> Registry entry SHA-256: \`${entryHash}\``,
    "",
    `- **Capability ID:** \`${capability.capability_id}\``,
    `- **Portfolio:** \`${capability.portfolio}\``,
    `- **Surface:** \`${capability.agent_surface}\``,
    `- **Authority:** \`${capability.authority}\``,
    "",
    "## Purpose",
    "",
    capability.purpose,
    "",
    "## Stage Entry",
    "",
    renderBullets(capability.stage_entry),
    "",
    "## Stage Exit",
    "",
    renderBullets(capability.stage_exit),
    "",
    "## Owns",
    "",
    renderBullets(capability.owns),
    "",
    "## May Advise",
    "",
    renderBullets(capability.may_advise),
    "",
    "## Must Not Decide",
    "",
    renderBullets(capability.must_not_decide),
    "",
    "## Required Context",
    "",
    renderBullets(capability.required_context),
    "",
    "## Knowledge Modules",
    "",
    renderBullets(capability.knowledge_modules.map((item) => `\`${item}\``)),
    "",
    "## Method Cards",
    "",
    renderBullets(capability.method_cards.map((item) => `\`${item}\``)),
    "",
    "## Tools",
    "",
    renderBullets(capability.tools),
    "",
    "## Skills",
    "",
    renderBullets(capability.skills.map((item) => `\`${item}\``)),
    "",
    "## Inputs",
    "",
    renderBullets(capability.inputs),
    "",
    "## Outputs",
    "",
    renderBullets(capability.outputs),
    "",
    "## Handoff To",
    "",
    renderBullets(capability.handoff_to.map((item) => `\`${item}\``)),
    "",
    "## Failure Modes",
    "",
    renderBullets(capability.failure_modes),
    "",
    "## Counterexamples",
    "",
    renderBullets(capability.counterexamples),
    "",
    "## Fixtures",
    "",
    `Profile: \`${capability.fixtures.profile}\``,
    "",
    renderBullets(capability.fixtures.seeds),
    "",
    "Required suite:",
    "",
    `- Normal: ${fixtureContract.normal}`,
    `- Overreach or role confusion: ${fixtureContract.overreach_or_role_confusion}`,
    `- Evidence gap or conflict: ${fixtureContract.evidence_gap_or_conflict}`,
    `- Adjacent-role handoff: ${fixtureContract.adjacent_role_handoff}`,
    `- Ablation: ${fixtureContract.ablation}`,
    `- Real artifact review: ${fixtureContract.real_artifact_review}`,
    `- Blind review required: ${fixtureContract.blind_review_required}`,
    "",
    "## Ablation Claim",
    "",
    capability.ablation_claim,
    "",
  ];
  return lines.join("\n");
}

function renderAgentToml(registry, capability) {
  const runtime = registry.agent_runtime;
  const packagePath = `${packageDirectory(capability.capability_id)}/capability.json`;
  const markdownPath = `${packageDirectory(capability.capability_id)}/CAPABILITY.md`;
  const instructions = [
    `You are the TCIS v3 specialist ${capability.capability_id} (${capability.display_role}).`,
    `Before acting, read \`${packagePath}\` and \`${markdownPath}\`.`,
    "The JSON package is the sole role, authority, stage, method, tool, skill, input, output, failure, fixture, and ablation contract.",
    `Default response language: ${runtime.default_language}.`,
    "",
    "Shared runtime rules:",
    ...runtime.shared_instructions.map((instruction) => `- ${instruction}`),
  ].join("\n");

  const description = `TCIS v3 specialist entry for ${capability.display_role}; canonical package: ${packagePath}`;
  return [
    GENERATED_HEADER,
    `name = ${JSON.stringify(capability.capability_id)}`,
    `description = ${JSON.stringify(description)}`,
    `model_reasoning_effort = ${JSON.stringify(runtime.model_reasoning_effort)}`,
    `sandbox_mode = ${JSON.stringify(runtime.sandbox_mode)}`,
    "developer_instructions = \"\"\"",
    instructions,
    "\"\"\"",
    "",
  ].join("\n");
}

function renderRegistryReadme(registry) {
  const core = registry.capabilities.filter((capability) => capability.portfolio === "core");
  const conditional = registry.capabilities.filter(
    (capability) => capability.portfolio === "conditional",
  );
  const rows = registry.capabilities.map((capability) => {
    const surface =
      capability.agent_surface === "main-thread"
        ? "main-thread package only"
        : `\`.codex/agents/${agentFileName(capability.capability_id)}\``;
    return `| \`${capability.capability_id}\` | ${capability.display_role} | ${capability.portfolio} | ${surface} |`;
  });
  return [
    "# TCIS v3 Capability Registry",
    "",
    "> Generated index. `capabilities/registry.json` is the only authored role-truth source.",
    "",
    `- Core capabilities: ${core.length}`,
    `- Conditional capabilities: ${conditional.length}`,
    `- Generated specialist TOMLs: ${registry.capabilities.length - 1}`,
    "- Creative Lead surface: main-thread package only",
    "",
    "| Capability ID | Display Role | Portfolio | Runtime Surface |",
    "|---|---|---|---|",
    ...rows,
    "",
  ].join("\n");
}

function createPackage(registry, capability) {
  const entryHash = sha256(canonicalJson(capability));
  return {
    package: {
      schema_version: "tcis-capability-package.v3",
      generated: {
        generator: "tools/generate-agent-configs.mjs",
        source: REGISTRY_RELATIVE_PATH,
        registry_id: registry.registry_id,
        registry_entry_sha256: entryHash,
      },
      source_documents: registry.source_documents,
      fixture_contract: registry.fixture_profiles[capability.fixtures.profile],
      ...capability,
    },
    entryHash,
  };
}

export function buildArtifacts(registry) {
  validateRegistry(registry);
  const artifacts = new Map();
  artifacts.set("capabilities/README.md", renderRegistryReadme(registry));

  for (const capability of registry.capabilities) {
    const directory = packageDirectory(capability.capability_id);
    const { package: capabilityPackage, entryHash } = createPackage(registry, capability);
    artifacts.set(`${directory}/capability.json`, canonicalJson(capabilityPackage));
    artifacts.set(
      `${directory}/CAPABILITY.md`,
      renderCapabilityMarkdown(registry, capability, entryHash),
    );
    if (capability.agent_surface === "custom-agent") {
      artifacts.set(
        `.codex/agents/${agentFileName(capability.capability_id)}`,
        renderAgentToml(registry, capability),
      );
    }
  }

  const generatedFiles = [...artifacts.entries()]
    .sort(([left], [right]) => left.localeCompare(right, "en"))
    .map(([relativePath, content]) => ({
      path: relativePath,
      sha256: sha256(content),
    }));
  const customAgentIds = registry.capabilities
    .filter((capability) => capability.agent_surface === "custom-agent")
    .map((capability) => capability.capability_id);
  const mainThreadCapabilityIds = registry.capabilities
    .filter((capability) => capability.agent_surface === "main-thread")
    .map((capability) => capability.capability_id);
  artifacts.set(
    GENERATED_MANIFEST_PATH,
    canonicalJson({
      schema_version: "tcis-generated-manifest.v1",
      source: REGISTRY_RELATIVE_PATH,
      registry_sha256: sha256(canonicalJson(registry)),
      custom_agent_ids: customAgentIds,
      main_thread_capability_ids: mainThreadCapabilityIds,
      generated_files: generatedFiles,
    }),
  );

  return artifacts;
}

async function readTextIfPresent(absolutePath) {
  try {
    return await readFile(absolutePath, "utf8");
  } catch (error) {
    if (error && error.code === "ENOENT") {
      return null;
    }
    throw error;
  }
}

function resolveGeneratedPath(relativePath) {
  assert(
    isGeneratedArtifactPath(relativePath),
    `invalid generated relative path: ${relativePath}`,
  );
  const absolutePath = path.resolve(ROOT, relativePath);
  const relativeToRoot = path.relative(ROOT, absolutePath);
  assert(
    relativeToRoot !== "" &&
      !relativeToRoot.startsWith(`..${path.sep}`) &&
      relativeToRoot !== ".." &&
      !path.isAbsolute(relativeToRoot),
    `generated path escapes repository root: ${relativePath}`,
  );
  return absolutePath;
}

async function listFilesRecursive(directory) {
  const results = [];
  let entries;
  try {
    entries = await readdir(directory, { withFileTypes: true });
  } catch (error) {
    if (error && error.code === "ENOENT") {
      return results;
    }
    throw error;
  }
  entries.sort((left, right) => left.name.localeCompare(right.name, "en"));
  for (const entry of entries) {
    const absolutePath = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      results.push(...(await listFilesRecursive(absolutePath)));
    } else if (entry.isFile()) {
      results.push(absolutePath);
    }
  }
  return results;
}

async function loadPreviousGeneratedPaths() {
  const manifestText = await readTextIfPresent(resolveGeneratedPath(GENERATED_MANIFEST_PATH));
  if (manifestText === null) {
    return [];
  }
  try {
    const manifest = JSON.parse(manifestText);
    if (!Array.isArray(manifest.generated_files)) {
      return [];
    }
    return [
      ...new Set(
        manifest.generated_files
          .map((entry) => entry && entry.path)
          .filter(isCleanupEligibleGeneratedPath),
      ),
    ];
  } catch {
    return [];
  }
}

async function assertNoSymlinkedParent(absolutePath) {
  const relativeParent = path.relative(ROOT, path.dirname(absolutePath));
  let current = ROOT;
  for (const segment of relativeParent.split(path.sep).filter(Boolean)) {
    current = path.join(current, segment);
    try {
      const stats = await lstat(current);
      assert(
        !stats.isSymbolicLink(),
        `generated cleanup path has a symbolic-link parent: ${toPosix(path.relative(ROOT, absolutePath))}`,
      );
    } catch (error) {
      if (error && error.code === "ENOENT") {
        return;
      }
      throw error;
    }
  }
}

async function removeGeneratedProjection(relativePath) {
  assert(
    isCleanupEligibleGeneratedPath(relativePath),
    `path is not eligible for generated cleanup: ${relativePath}`,
  );
  const absolutePath = resolveGeneratedPath(relativePath);
  await assertNoSymlinkedParent(absolutePath);
  await rm(absolutePath, { force: true });
  return absolutePath;
}

async function removeEmptyParents(startDirectory, stopDirectory) {
  let current = startDirectory;
  const stop = path.resolve(stopDirectory);
  while (current.startsWith(`${stop}${path.sep}`)) {
    let entries;
    try {
      entries = await readdir(current);
    } catch (error) {
      if (error && error.code === "ENOENT") {
        return;
      }
      throw error;
    }
    if (entries.length > 0) {
      return;
    }
    await rm(current, { recursive: false });
    current = path.dirname(current);
  }
}

export async function writeArtifacts(registry, artifacts) {
  const expectedPaths = new Set(artifacts.keys());
  const previousPaths = await loadPreviousGeneratedPaths();
  const stalePaths = previousPaths.filter((relativePath) => !expectedPaths.has(relativePath));

  for (const legacyFile of registry.migration.legacy_agent_files) {
    const relativePath = `.codex/agents/${legacyFile}`;
    await removeGeneratedProjection(relativePath);
  }

  const currentAgentFiles = await listFilesRecursive(path.join(ROOT, ".codex", "agents"));
  for (const absolutePath of currentAgentFiles) {
    if (path.extname(absolutePath) !== ".toml") {
      continue;
    }
    const text = await readTextIfPresent(absolutePath);
    const relativePath = toPosix(path.relative(ROOT, absolutePath));
    if (
      isCleanupEligibleGeneratedPath(relativePath) &&
      text?.startsWith(GENERATED_HEADER) &&
      !expectedPaths.has(relativePath)
    ) {
      await removeGeneratedProjection(relativePath);
    }
  }

  for (const relativePath of stalePaths) {
    const absolutePath = await removeGeneratedProjection(relativePath);
    if (isCapabilityProjectionPath(relativePath)) {
      await removeEmptyParents(path.dirname(absolutePath), path.join(ROOT, "capabilities"));
    }
  }

  const sortedArtifacts = [...artifacts.entries()].sort(([left], [right]) =>
    left.localeCompare(right, "en"),
  );
  for (const [relativePath, content] of sortedArtifacts) {
    const absolutePath = resolveGeneratedPath(relativePath);
    await mkdir(path.dirname(absolutePath), { recursive: true });
    await writeFile(absolutePath, content, "utf8");
  }
}

export async function checkArtifacts(registry, artifacts, registryText) {
  const errors = [];
  if (registryText !== canonicalJson(registry)) {
    errors.push(`${REGISTRY_RELATIVE_PATH} is not canonically formatted`);
  }

  for (const [relativePath, expectedContent] of artifacts) {
    const actualContent = await readTextIfPresent(resolveGeneratedPath(relativePath));
    if (actualContent === null) {
      errors.push(`missing generated file: ${relativePath}`);
    } else if (actualContent !== expectedContent) {
      errors.push(`generated file drift: ${relativePath}`);
    }
  }

  const expectedAgentPaths = new Set(
    [...artifacts.keys()].filter((relativePath) => relativePath.startsWith(".codex/agents/")),
  );
  const actualAgentFiles = (await listFilesRecursive(path.join(ROOT, ".codex", "agents")))
    .filter((absolutePath) => path.extname(absolutePath) === ".toml")
    .map((absolutePath) => toPosix(path.relative(ROOT, absolutePath)));
  for (const relativePath of actualAgentFiles) {
    if (!expectedAgentPaths.has(relativePath)) {
      errors.push(`unexpected active agent TOML: ${relativePath}`);
    }
  }

  const expectedCapabilityPaths = new Set([
    REGISTRY_RELATIVE_PATH,
    ...[...artifacts.keys()].filter((relativePath) => relativePath.startsWith("capabilities/")),
  ]);
  const actualCapabilityFiles = (await listFilesRecursive(path.join(ROOT, "capabilities"))).map(
    (absolutePath) => toPosix(path.relative(ROOT, absolutePath)),
  );
  for (const relativePath of actualCapabilityFiles) {
    if (!expectedCapabilityPaths.has(relativePath)) {
      errors.push(`unexpected capability registry artifact: ${relativePath}`);
    }
  }

  if (errors.length > 0) {
    fail(`TCIS generated-surface check failed:\n- ${errors.join("\n- ")}`);
  }
}

export async function loadRegistry() {
  const registryText = await readFile(REGISTRY_PATH, "utf8");
  let registry;
  try {
    registry = JSON.parse(registryText);
  } catch (error) {
    fail(`invalid JSON in ${REGISTRY_RELATIVE_PATH}: ${error.message}`);
  }
  validateRegistry(registry);
  return { registry, registryText };
}

export async function run(mode = "write") {
  const { registry, registryText } = await loadRegistry();
  const artifacts = buildArtifacts(registry);
  if (mode === "check") {
    await checkArtifacts(registry, artifacts, registryText);
    return {
      mode,
      capabilityCount: registry.capabilities.length,
      agentCount: registry.capabilities.filter(
        (capability) => capability.agent_surface === "custom-agent",
      ).length,
      artifactCount: artifacts.size,
    };
  }
  if (mode !== "write") {
    fail(`unsupported mode: ${mode}`);
  }
  await writeArtifacts(registry, artifacts);
  return {
    mode,
    capabilityCount: registry.capabilities.length,
    agentCount: registry.capabilities.filter(
      (capability) => capability.agent_surface === "custom-agent",
    ).length,
    artifactCount: artifacts.size,
  };
}

const isMain = process.argv[1]
  ? import.meta.url === pathToFileURL(path.resolve(process.argv[1])).href
  : false;

if (isMain) {
  const mode = process.argv.includes("--check") ? "check" : "write";
  try {
    const result = await run(mode);
    console.log(
      `TCIS v3 ${result.mode}: ${result.capabilityCount} capabilities, ${result.agentCount} specialist TOMLs, ${result.artifactCount} generated artifacts`,
    );
  } catch (error) {
    console.error(error.message);
    process.exitCode = 1;
  }
}
